import React from 'react';
import './contactus.css';

const ContactUs = () => {
  return (
    <div className="contact-us">
      <div className="text-message">
        <h1>Transform Your Life with Nutritional Expertise</h1>
        <p>Use our contact form for all information requests or contact us directly using the contact information below.</p>
        <h2>Get in Touch to Begin Your Wellness Journey</h2>
      </div>
      <div className="contact-informations">
        Contact Information Content
      </div>
      <div className="contact-form">
        Contact Form Content
      </div>
    </div>
  );
};

export default ContactUs;
